import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

function Home() {
    const [osList, setOsList] = useState([]);
    const [filtroNumero, setFiltroNumero] = useState('');
    const [filtroStatus, setFiltroStatus] = useState('todos');
    const [filtroCliente, setFiltroCliente] = useState('');
    const [pagina, setPagina] = useState(1);
    const itensPorPagina = 10;

    // Estatísticas gerais
    const [totalAbertas, setTotalAbertas] = useState(0);
    const [totalConcluidas, setTotalConcluidas] = useState(0);
    const [faturamentoMesCorrente, setFaturamentoMesCorrente] = useState(0);
    const [clientes, setClientes] = useState([]);

    // Filtros de faturamento personalizado
    const [filtroFaturamento, setFiltroFaturamento] = useState('geral'); // 'dia', 'mes', 'cliente', 'geral'
    const [filtroDataDia, setFiltroDataDia] = useState(new Date().toISOString().slice(0,10));
    const [filtroMesAno, setFiltroMesAno] = useState(`${new Date().getFullYear()}-${String(new Date().getMonth()+1).padStart(2,'0')}`);
    const [filtroClienteId, setFiltroClienteId] = useState('');
    const [faturamentoFiltrado, setFaturamentoFiltrado] = useState(0);

    useEffect(() => {
        carregarOS();
        carregarClientes();
    }, []);

    const carregarClientes = async () => {
        try {
            const res = await api.get('/clientes');
            setClientes(res.data);
        } catch (err) { console.error(err); }
    };

    const carregarOS = async () => {
        try {
            const res = await api.get('/os');
            const data = res.data;
            setOsList(data);
            calcularEstatisticas(data);
        } catch (err) { console.error(err); }
    };

    const calcularEstatisticas = (data) => {
        // OS abertas e concluídas
        const abertas = data.filter(os => os.status_os !== 'concluido').length;
        const concluidas = data.filter(os => os.status_os === 'concluido').length;
        setTotalAbertas(abertas);
        setTotalConcluidas(concluidas);

        // Faturamento do mês corrente (data atual)
        const hoje = new Date();
        const mesAtual = hoje.getMonth();
        const anoAtual = hoje.getFullYear();
        const fatMesCorrente = data.reduce((acc, os) => {
            if (os.status_os === 'concluido' && os.data_conclusao) {
                const dataConc = new Date(os.data_conclusao);
                if (dataConc.getMonth() === mesAtual && dataConc.getFullYear() === anoAtual) {
                    const total = (parseFloat(os.preco_final) || 0) + (parseFloat(os.valor_deslocamento) || 0);
                    return acc + total;
                }
            }
            return acc;
        }, 0);
        setFaturamentoMesCorrente(fatMesCorrente);
    };

    // Calcula faturamento filtrado sempre que os filtros mudarem
    useEffect(() => {
        if (osList.length === 0) return;
        let filtradas = osList.filter(os => os.status_os === 'concluido');

        if (filtroFaturamento === 'dia') {
            filtradas = filtradas.filter(os => os.data_conclusao === filtroDataDia);
        } else if (filtroFaturamento === 'mes') {
            const [ano, mes] = filtroMesAno.split('-');
            filtradas = filtradas.filter(os => {
                const data = new Date(os.data_conclusao);
                return data.getFullYear() === parseInt(ano) && (data.getMonth()+1) === parseInt(mes);
            });
        } else if (filtroFaturamento === 'cliente') {
            if (filtroClienteId) {
                filtradas = filtradas.filter(os => os.cliente_id === parseInt(filtroClienteId));
            } else {
                filtradas = [];
            }
        }

        const total = filtradas.reduce((acc, os) => {
            const valor = (parseFloat(os.preco_final) || 0) + (parseFloat(os.valor_deslocamento) || 0);
            return acc + valor;
        }, 0);
        setFaturamentoFiltrado(total);
    }, [osList, filtroFaturamento, filtroDataDia, filtroMesAno, filtroClienteId]);

    const aplicarFiltroFaturamento = (tipo) => {
        setFiltroFaturamento(tipo);
    };

    // Filtros para listagem de OS (já existentes)
    const osFiltradas = osList.filter(os => {
        if (filtroNumero && !os.numero_os?.toLowerCase().includes(filtroNumero.toLowerCase())) return false;
        if (filtroStatus === 'abertos' && os.status_os === 'concluido') return false;
        if (filtroStatus === 'concluidos' && os.status_os !== 'concluido') return false;
        if (filtroCliente && !os.cliente_nome?.toLowerCase().includes(filtroCliente.toLowerCase())) return false;
        return true;
    });

    const totalPaginas = Math.ceil(osFiltradas.length / itensPorPagina);
    const osExibidas = osFiltradas.slice((pagina-1)*itensPorPagina, pagina*itensPorPagina);

    return (
        <div>
            <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                <h1 className="card" style={{ display: 'inline-block', background: 'linear-gradient(135deg, #1e3c72, #2a5298)', color: 'white', padding: '12px 28px', borderRadius: '60px', fontSize: '1.8rem' }}>
                    📊 DASHBOARD - MWR SISTEMA
                </h1>
            </div>

            {/* Cards de estatísticas rápidas */}
            <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', marginBottom: '30px', flexWrap: 'wrap' }}>
                <div className="card" style={{ width: '200px', textAlign: 'center', borderTop: '5px solid #ffc107' }}>
                    <div style={{ fontSize: '2.2rem' }}>🟠</div>
                    <div><strong>OS Abertas</strong></div>
                    <div style={{ fontSize: '28px', fontWeight: 'bold' }}>{totalAbertas}</div>
                </div>
                <div className="card" style={{ width: '200px', textAlign: 'center', borderTop: '5px solid #28a745' }}>
                    <div style={{ fontSize: '2.2rem' }}>✅</div>
                    <div><strong>OS Concluídas</strong></div>
                    <div style={{ fontSize: '28px', fontWeight: 'bold' }}>{totalConcluidas}</div>
                </div>
                <div className="card" style={{ width: '200px', textAlign: 'center', borderTop: '5px solid #007bff' }}>
                    <div style={{ fontSize: '2.2rem' }}>💰</div>
                    <div><strong>Faturamento do mês</strong></div>
                    <div style={{ fontSize: '22px', fontWeight: 'bold' }}>R$ {faturamentoMesCorrente.toFixed(2)}</div>
                </div>
            </div>

            {/* Painel de consulta de faturamento */}
            <div className="card">
                <h3>🔍 Consultar faturamento</h3>
                <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap', alignItems: 'flex-end', marginBottom: '20px' }}>
                    <div>
                        <button className="btn btn-primary" onClick={() => aplicarFiltroFaturamento('geral')}>📊 Total acumulado</button>
                    </div>
                    <div>
                        <button className="btn btn-primary" onClick={() => aplicarFiltroFaturamento('dia')}>📅 Por dia</button>
                        {filtroFaturamento === 'dia' && (
                            <input type="date" value={filtroDataDia} onChange={e => setFiltroDataDia(e.target.value)} style={{ marginLeft: '8px' }} />
                        )}
                    </div>
                    <div>
                        <button className="btn btn-primary" onClick={() => aplicarFiltroFaturamento('mes')}>📆 Por mês</button>
                        {filtroFaturamento === 'mes' && (
                            <input type="month" value={filtroMesAno} onChange={e => setFiltroMesAno(e.target.value)} style={{ marginLeft: '8px' }} />
                        )}
                    </div>
                    <div>
                        <button className="btn btn-primary" onClick={() => aplicarFiltroFaturamento('cliente')}>👤 Por cliente</button>
                        {filtroFaturamento === 'cliente' && (
                            <select value={filtroClienteId} onChange={e => setFiltroClienteId(e.target.value)} style={{ marginLeft: '8px' }}>
                                <option value="">Selecione um cliente</option>
                                {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                            </select>
                        )}
                    </div>
                </div>
                <div style={{ background: '#f0f8ff', padding: '15px', borderRadius: '12px' }}>
                    <strong>Resultado:</strong> R$ {faturamentoFiltrado.toFixed(2)}
                </div>
            </div>

            {/* Filtros da lista de OS */}
            <div className="filtros-container">
                <input type="text" placeholder="🔍 Nº da OS" value={filtroNumero} onChange={e => setFiltroNumero(e.target.value)} style={{ flex: 1 }} />
                <select value={filtroStatus} onChange={e => setFiltroStatus(e.target.value)}>
                    <option value="todos">Todos status</option>
                    <option value="abertos">Somente abertos</option>
                    <option value="concluidos">Somente concluídos</option>
                </select>
                <input type="text" placeholder="👤 Nome do cliente" value={filtroCliente} onChange={e => setFiltroCliente(e.target.value)} style={{ flex: 1 }} />
            </div>

            {/* Tabela de OS */}
            <div className="table-responsive">
                <table style={{ width: '100%' }}>
                    <thead>
                        <tr>
                            <th>Nº OS</th><th>Cliente</th><th>Equipamento</th><th>Status</th><th>Valor Total</th><th>Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {osExibidas.length === 0 ? (
                            <tr><td colSpan="6" style={{ textAlign: 'center', padding: '40px' }}>Nenhuma OS encontrada</td></tr>
                        ) : (
                            osExibidas.map(os => {
                                const totalValor = (parseFloat(os.preco_final) + parseFloat(os.valor_deslocamento || 0)).toFixed(2);
                                return (
                                    <tr key={os.id}>
                                        <td>{os.numero_os}</td>
                                        <td>{os.cliente_nome}</td>
                                        <td>{os.equipamento} {os.modelo}</td>
                                        <td><span style={{ backgroundColor: os.status_os === 'concluido' ? '#28a745' : '#ffc107', padding: '4px 10px', borderRadius: '30px', fontSize: '12px', fontWeight: 'bold' }}>{os.status_os === 'concluido' ? 'CONCLUÍDO' : 'ABERTO'}</span></td>
                                        <td>R$ {totalValor}</td>
                                        <td>
                                            <Link to={`/os/${os.id}`}><button className="btn btn-primary" style={{ marginRight: '5px' }}>Ver</button></Link>
                                            <Link to={`/os/editar/${os.id}`}><button className="btn btn-warning">Editar</button></Link>
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {/* Paginação */}
            {totalPaginas > 1 && (
                <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginTop: '20px' }}>
                    <button className="btn btn-secondary" onClick={() => setPagina(p => Math.max(1, p-1))} disabled={pagina === 1}>Anterior</button>
                    <span>Página {pagina} de {totalPaginas}</span>
                    <button className="btn btn-secondary" onClick={() => setPagina(p => Math.min(totalPaginas, p+1))} disabled={pagina === totalPaginas}>Próxima</button>
                </div>
            )}
        </div>
    );
}

export default Home;
